    static singleOrDefault<T>(items: readonly T[], predicate?: ((item: T) => boolean) | null, defaultValue?: T | null): T | null;
    static skip<T>(items: readonly T[], count: number): T[];
    static skipLast<T>(items: readonly T[], count: number): T[];
    static skipWhile<T>(items: readonly T[], predicate: (item: T, index: number) => boolean): T[];
    static first<T>(items: readonly T[], predicate?: ((item: T) => boolean) | null, defaultValue?: T | null): T;
    static firstOrDefault<T>(items: readonly T[], predicate?: ((item: T) => boolean) | null, defaultValue?: T | null): T | null;
    static last<T>(items: readonly T[], predicate?: ((item: T) => boolean) | null, defaultValue?: T | null): T;
    static lastOrDefault<T>(items: readonly T[], predicate?: ((item: T) => boolean) | null, defaultValue?: T | null): T | null;
    static forEachAsync<T>(items: readonly T[], predicate: (item: T) => Promise<void>): Promise<void>;
    static except<T>(items: readonly T[], except: readonly T[], comparer?: ((x: T, y: T) => boolean) | null): T[];
