    static remove<T>(items: T[], item: T | T[] | ((item: T, index: number) => boolean)): void;
    static removeAt<T>(items: T[], index: number): void;
    static max<T>(items: readonly T[], keySelector?: ((item: T) => number) | null): T;
    static maxValue<T>(items: readonly T[], keySelector: (item: T) => number): number;
    static min<T, TValue = number | Date>(items: readonly T[], keySelector?: ((item: T) => TValue) | null): T;
    static minValue<T, TValue = number | Date>(items: readonly T[], predicate: (item: T) => TValue): TValue;
    static sum<T>(items: readonly T[] | null | undefined, selector?: ((item: T) => number | null | undefined) | null): number;
