    static contains<T>(items: readonly T[], value: T): boolean;
    static distinct<T>(items: readonly T[], predicate?: ((item: T) => any) | null): T[];
    static repeat<T>(element: T, count: number): T[];
    static insert<T>(items: T[], item: T | readonly T[], index?: number | null): void;
    static average<T>(items: readonly T[], selector?: ((item: T) => number | null | undefined) | null): number;
    static sortBy<T, TKey1, TKey2, TKey3, TKey4, TKey5, TKey6>(source: T[], keySelector1?: ((item: T) => TKey1) | null, keySelector2?: ((item: T) => TKey2) | null, keySelector3?: ((item: T) => TKey3) | null, keySelector4?: ((item: T) => TKey4) | null, keySelector5?: ((item: T) => TKey5) | null, keySelector6?: ((item: T) => TKey6) | null): void;
    static sortByDescending<T, TKey1, TKey2, TKey3, TKey4, TKey5, TKey6>(source: T[], keySelector1?: ((item: T) => TKey1) | null, keySelector2?: ((item: T) => TKey2) | null, keySelector3?: ((item: T) => TKey3) | null, keySelector4?: ((item: T) => TKey4) | null, keySelector5?: ((item: T) => TKey5) | null, keySelector6?: ((item: T) => TKey6) | null): void;
